(2, 1, '870548f7-5f37-45b4-bcb2-61932a229eff', 'superadmin', 'id', 1, 'Maaf, saya hanya dapat membantu terkait penggunaan aplikasi Absensi PKL.', 'dynamic.out_of_scope', 1.0000, '2026-04-27 00:24:22', '2026-04-27 00:24:22'),
