(4, 1324, '83254fa0-a319-4db1-b72a-1e7ca20b3892', 'siswa', 'id', 1, 'Untuk check-in: buka Absensi Harian, masuk ke Check-in, ambil foto dari kamera, pastikan lokasi aktif, lalu kirim. Status akan masuk pending validasi.\n\nLetaknya di menu `Absensi Harian` dengan URL `/absensi`.', 'siswa.checkin', 1.0000, '2026-04-27 05:10:06', '2026-04-27 05:10:06'),
(5, 5, '672aef23-1c08-48cc-bed3-825bd9bef5a6', 'instruktur', 'en', 0, 'What does pending mean in weekly notes?', NULL, NULL, '2026-04-27 07:31:13', '2026-04-27 07:31:13'),
(6, 5, '672aef23-1c08-48cc-bed3-825bd9bef5a6', 'instruktur', 'en', 1, 'Sorry, you do not have access to that data. Please ask about menus and data available to your current role.', 'global.permission', 0.2775, '2026-04-27 07:31:13', '2026-04-27 07:31:13'),
(7, 5, '672aef23-1c08-48cc-bed3-825bd9bef5a6', 'instruktur', 'en', 0, 'What does pending mean in weekly notes?', NULL, NULL, '2026-04-27 07:33:45', '2026-04-27 07:33:45'),
(8, 5, '672aef23-1c08-48cc-bed3-825bd9bef5a6', 'instruktur', 'en', 1, 'Pending means the data is still waiting for the next process in that menu workflow. For weekly notes, pending means that week/note has not been finalized in the next evaluation step yet.', 'global.pending_status', 1.0000, '2026-04-27 07:33:45', '2026-04-27 07:33:45'),
(9, 5, '672aef23-1c08-48cc-bed3-825bd9bef5a6', 'instruktur', 'en', 0, 'What does weekly validation mean?', NULL, NULL, '2026-04-27 07:34:05', '2026-04-27 07:34:05'),
(10, 5, '672aef23-1c08-48cc-bed3-825bd9bef5a6', 'instruktur', 'en', 1, 'Pending means the data is still waiting for the next process in that menu workflow. For weekly notes, pending means that week/note has not been finalized in the next evaluation step yet.', 'global.pending_status', 0.3769, '2026-04-27 07:34:05', '2026-04-27 07:34:05');
